<style>
/* Homepage-specific styling. Move this block to styles.css later if desired. */
.homepage {
  --home-accent: #426b73;
  --home-accent-soft: #e7f0f1;
  --home-ink: #1f2933;
  --home-muted: #5f6f7a;
  --home-line: #d7e1e4;
  --home-bg: #ffffff;
  font-size: 1.02rem;
}

.home-hero {
  min-height: 72vh;
  display: grid;
  align-items: center;
  background:
    linear-gradient(rgba(255,255,255,0.22), rgba(255,255,255,0.90)),
    url("images/black-mt-peninsula.jpg") center / cover no-repeat;
  border-bottom: 1px solid var(--home-line);
  margin-top: -1.5rem;
}

.home-hero-inner {
  max-width: 1120px;
  margin: 0 auto;
  padding: 5.5rem 1.5rem 4.5rem;
}

.home-kicker {
  text-transform: uppercase;
  letter-spacing: 0.14em;
  font-size: 0.78rem;
  color: var(--home-accent);
  font-weight: 700;
  margin-bottom: 1rem;
}

.home-title {
  font-size: clamp(2.4rem, 7vw, 5.2rem);
  line-height: 0.95;
  font-weight: 700;
  margin: 0 0 1.1rem;
  color: var(--home-ink);
}

.home-subtitle {
  max-width: 760px;
  font-size: clamp(1.1rem, 2vw, 1.55rem);
  line-height: 1.45;
  color: var(--home-muted);
  margin-bottom: 1.7rem;
}

.home-actions {
  display: flex;
  gap: 0.8rem;
  flex-wrap: wrap;
}

.home-btn {
  display: inline-block;
  padding: 0.72rem 1rem;
  border-radius: 999px;
  text-decoration: none;
  font-weight: 650;
  border: 1px solid var(--home-accent);
}

.home-btn.primary {
  background: var(--home-accent);
  color: white;
}

.home-btn.secondary {
  color: var(--home-accent);
  background: rgba(255,255,255,0.75);
}

.home-section {
  max-width: 1120px;
  margin: 0 auto;
  padding: 4rem 1.5rem;
}

.home-section.narrow {
  max-width: 980px;
}

.home-about-grid {
  display: grid;
  grid-template-columns: minmax(130px, 2.5fr) minmax(0, 7.5fr);
  gap: 2rem;
  align-items: start;
}

.home-about-photo {
  width: 100%;
  aspect-ratio: 1 / 1;
  object-fit: cover;
  border-radius: 18px;
  background: var(--home-accent-soft);
  border: 1px solid var(--home-line);
  box-shadow: 0 8px 22px rgba(31, 41, 51, 0.05);
}

.home-section-title {
  font-size: clamp(1.6rem, 3vw, 2.3rem);
  margin: 0 0 1.2rem;
  color: var(--home-ink);
}

.home-lede {
  font-size: 1.13rem;
  line-height: 1.75;
  color: var(--home-ink);
}

.home-muted {
  color: var(--home-muted);
}

.home-two-col {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 2.2rem;
  align-items: center;
}

.home-portrait {
  border-radius: 22px;
  width: 100%;
  aspect-ratio: 4 / 3;
  object-fit: cover;
  background: var(--home-accent-soft);
  border: 1px solid var(--home-line);
}

.home-list-links {
  display: grid;
  gap: 0.75rem;
  margin-top: 1.2rem;
}

.home-list-links a {
  display: block;
  padding: 0.9rem 1rem;
  border: 1px solid var(--home-line);
  border-radius: 14px;
  text-decoration: none;
  color: var(--home-ink);
  background: white;
}

.home-list-links a span {
  color: var(--home-muted);
}

@media (max-width: 820px) {
  .home-two-col,
  .home-about-grid {
    grid-template-columns: 1fr;
  }

  .home-hero {
    min-height: auto;
  }
}
</style>

<div class="homepage">

<section class="home-hero">
  <div class="home-hero-inner">
    <div class="home-kicker">Mathematics · Cybernetics · Complexity</div>
    <h1 class="home-title">Sungyeon Hong</h1>
    <div class="home-subtitle">
      Transdisciplinary researcher and educator, studying how structure, behaviour, and meaning emerge in complex systems.
    </div>
    <div class="home-actions">
      <a class="home-btn primary" href="research.html">Explore research</a>
      <a class="home-btn secondary" href="contact.html">Get in touch</a>
    </div>
  </div>
</section>

<section class="home-section narrow">
  <h2 class="home-section-title">About</h2>
  <div class="home-about-grid">
    <div>
      <img class="home-about-photo" src="images/syh.jpg" alt="Portrait of Sungyeon Hong">
    </div>
    <div>
      <p class="home-lede home-muted">
        I am a Lecturer at the School of Cybernetics, Australian National University (ANU), in Canberra, Australia.
      </p>
      <p class="home-lede">
        My research sits at the intersection of topology, complexity science, cybernetics, and information dynamics. I study how structure emerges, evolves, and sometimes degrades in systems composed of many interacting parts—from geometric point patterns to human–AI communication systems and knowledge landscapes.
      </p>
      <p class="home-lede">
        Across these projects, I use topology not only as a mathematical toolkit, but as a way of seeing: a means of identifying shapes, holes, flows, and structural signatures that reveal how local interactions give rise to global phenomena.
      </p>
    </div>
  </div>
</section>


<section class="home-section">
  <div class="home-two-col">
    <div>
      <h2 class="home-section-title">Teaching, outreach, and public engagement</h2>
      <p class="home-lede">
        I teach across undergraduate, postgraduate, and non-award learning contexts, with an emphasis on helping learners reason with complexity, build conceptual tools, and engage responsibly with emerging technologies.
      </p>
      <div class="home-list-links">
        <a href="education.html"><strong>Education</strong><br><span>Teaching commitments and learning experiences</span></a>
        <a href="engagements.html"><strong>Engagements</strong><br><span>Talks, workshops, panels, and public activities</span></a>
        <a href="publications.html"><strong>Publications</strong><br><span>Selected papers and research outputs</span></a>
      </div>
    </div>
    <div>
      <img class="home-portrait" src="images/home-secondary-placeholder.jpg" alt="Placeholder image for teaching and public engagement">
    </div>
  </div>
</section>

</div>
```

